+fn comparison_runtime_version_pin<'a>(
+    pins: &'a BenchmarkRuntimePins,
+    runtime: RuntimeId,
+) -> &'a str {
+    match runtime {
+        RuntimeId::FrankenEngine => &pins.franken_engine,
+        RuntimeId::NodeLts => &pins.node_lts,
+        RuntimeId::BunStable => &pins.bun_stable,
+    }
