+fn comparison_parity_target(runtime: RuntimeId) -> Option<ParityTarget> {
+    match runtime {
+        RuntimeId::FrankenEngine => None,
+        RuntimeId::NodeLts => Some(ParityTarget::NodeJs),
+        RuntimeId::BunStable => Some(ParityTarget::Bun),
+    }
+}
